#include <bits/stdc++.h>
using namespace std;
int n,sum;
set<int> s;
void dfs(int last,int rest){
	//last代表上一次的选择，rest为剩余的边数
	if(rest==0){//如果没有边没被分组
		s.insert(sum/2);//存入答案
		return;
	}
	for(int i=last;i<=rest;i++){
		sum+=i*(n-i);//sum统计交点数
		dfs(i,rest-i);
		sum-=i*(n-i);//回溯
	}
}
int main(){
    scanf("%d",&n);
    dfs(1,n);
    printf("%d",s.size());
    //输出答案
    return 0;
}
